import { NextRequest, NextResponse } from 'next/server'
import Member from '@/models/Member'
import Payment from '@/models/Payment'
import Receipt from '@/models/Receipt'
import Setting from '@/models/Setting'
import User from '@/models/User'
import SectorUnit from '@/models/SectorUnit'
import MemberCategory from '@/models/MemberCategory'
import { executeQuery } from '@/lib/neo4j'
import { validateAuth } from '@/lib/api-middleware'

export async function POST(req: NextRequest) {
  const auth = await validateAuth(req)
  if (!auth || auth.user.role !== 'admin') {
    return NextResponse.json({ message: 'Unauthorized' }, { status: 401 })
  }

  try {
    // 1. Fetch all data from MySQL
    const [members, payments, receipts, settings, users, units, categories] = await Promise.all([
      Member.findAll(),
      Payment.findAll(),
      Receipt.findAll(),
      Setting.findAll(),
      User.findAll(),
      SectorUnit.findAll(),
      MemberCategory.findAll()
    ])

    // 2. Clear Neo4j
    await executeQuery('MATCH (n) DETACH DELETE n')

    // 3. Create Constraints
    await executeQuery('CREATE CONSTRAINT member_id IF NOT EXISTS FOR (m:Member) REQUIRE m.id IS UNIQUE')
    await executeQuery('CREATE CONSTRAINT payment_id IF NOT EXISTS FOR (p:Payment) REQUIRE p.id IS UNIQUE')

    // 4. Import Categories
    for (const cat of categories) {
      await executeQuery(
        'CREATE (c:Category {id: $id, name: $name})',
        { id: cat.id, name: cat.name }
      )
    }

    // 5. Import Units
    for (const unit of units) {
      await executeQuery(
        'CREATE (u:SectorUnit {id: $id, name: $name, type: $type})',
        { id: unit.id, name: unit.name, type: unit.type }
      )
    }

    // 6. Import Members
    for (const member of members) {
      const m = member.toJSON()
      await executeQuery(`
        CREATE (m:Member {
          id: $id,
          fullName: $fullName,
          memberId: $memberId,
          phone: $phone,
          membershipType: $membershipType,
          branch: $branch,
          sector: $sector,
          status: $status,
          contributionMonthlyFee: $monthlyFee,
          contributionAnnualFee: $annualFee
        })
        WITH m
        MATCH (c:Category {id: $categoryId})
        CREATE (m)-[:HAS_CATEGORY]->(c)
        WITH m
        MATCH (u:SectorUnit {id: $unitId})
        CREATE (m)-[:BELONGS_TO]->(u)
      `, {
        id: m.id,
        fullName: m.fullName,
        memberId: m.memberId,
        phone: m.phone,
        membershipType: m.membershipType,
        branch: m.branch,
        sector: m.sector,
        status: m.status,
        monthlyFee: m.contributionMonthlyFee,
        annualFee: m.contributionAnnualFee,
        categoryId: m.memberCategoryId,
        unitId: m.sectorUnitId
      })
    }

    // 7. Import Payments
    for (const payment of payments) {
      const p = payment.toJSON()
      await executeQuery(`
        CREATE (p:Payment {
          id: $id,
          amount: $amount,
          method: $method,
          periodMonth: $month,
          periodYear: $year,
          status: $status,
          paymentDate: $date
        })
        WITH p
        MATCH (m:Member {id: $memberId})
        CREATE (m)-[:MADE_PAYMENT]->(p)
      `, {
        id: p.id,
        amount: p.amount,
        method: p.method,
        month: p.periodMonth,
        year: p.periodYear,
        status: p.status,
        date: p.paymentDate?.toISOString(),
        memberId: p.memberDbId
      })
    }

    return NextResponse.json({
      success: true,
      message: 'Data successfully migrated from MySQL to Neo4j',
      stats: {
        members: members.length,
        payments: payments.length,
        units: units.length,
        categories: categories.length
      }
    })
  } catch (error: any) {
    return NextResponse.json({ success: false, message: error.message }, { status: 500 })
  }
}
